const logicItem = $('Get EUR Logic Document').first().json;
const marketItem = $('Build EUR Input Pack').first().json;

let logicDocument = logicItem.content || '';

if (logicItem.encoding === 'base64') {
  logicDocument = Buffer.from(logicDocument, 'base64').toString('utf8');
}

return [
  {
    json: {
      logic_document: logicDocument,
      market_snapshot: marketItem
    }
  }
];

const rows = $input.all().map(item => item.json);

function hasValue(v) {
  return v !== null && v !== undefined && v !== '';
}

function parseQuality(row) {
  if (!row.data_quality) return {};
  if (typeof row.data_quality === 'object') return row.data_quality;
  try {
    return JSON.parse(row.data_quality);
  } catch {
    return {};
  }
}

function parseMaybeJson(v) {
  if (!hasValue(v)) return null;
  if (typeof v === 'object') return v;
  try {
    return JSON.parse(v);
  } catch {
    return v;
  }
}

function numOrNull(v) {
  if (!hasValue(v)) return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function isUsableEurSnapshot(row) {
  if (!row.snapshot_date || !row.run_time_et) return false;

  const required = [
    'vix_level',
    'dxy_level',
    'de_2y_yield',
    'de_2y_d5_bps',
    'us_de_2y_spread',
    'us_de_2y_spread_d5_bps',
    'eurusd_price',
    'eurusd_d1_pct',
    'eurusd_d5_pct',
    'ecb_bias'
  ];

  return required.every(key => hasValue(row[key]));
}

const sortedRows = rows
  .filter(r => r.snapshot_date && r.run_time_et)
  .sort((a, b) => {
    const bTime = new Date(b.run_time_et || b.created_at || 0).getTime();
    const aTime = new Date(a.run_time_et || a.created_at || 0).getTime();
    return bTime - aTime;
  });

const snapshot =
  sortedRows.find(r => r.collector_version === 'v11_eur_forex_factory_events' && isUsableEurSnapshot(r)) ||
  sortedRows.find(isUsableEurSnapshot) ||
  sortedRows[0];

if (!snapshot) {
  throw new Error("No valid market snapshot found");
}

const quality = parseQuality(snapshot);

const missingInputs = [];
const selectedInputWarnings = [];

function requireInput(key, label = key) {
  const value = snapshot[key];
  if (!hasValue(value)) {
    missingInputs.push(label);
    return null;
  }
  return value;
}

const goldD5 = hasValue(snapshot.gold_d5_pct)
  ? snapshot.gold_d5_pct
  : snapshot.gold_d1_pct;

if (!hasValue(snapshot.gold_d5_pct) && hasValue(snapshot.gold_d1_pct)) {
  selectedInputWarnings.push("gold_d5_pct missing; using gold_d1_pct fallback");
}

const selectedBy = snapshot.collector_version === 'v11_eur_forex_factory_events' && isUsableEurSnapshot(snapshot)
  ? "latest_v11_eur_usable_snapshot"
  : isUsableEurSnapshot(snapshot)
    ? "latest_eur_usable_snapshot"
    : "latest_available_snapshot_fallback";

const debugTopRows = sortedRows.slice(0, 5).map((r, index) => ({
  rank: index + 1,
  id: r.id,
  created_at: r.created_at,
  run_time_et: r.run_time_et,
  snapshot_date: r.snapshot_date,
  source_status: r.source_status,
  collector_version: r.collector_version,

  ecb_bias: r.ecb_bias,
  fed_bias: r.fed_bias,

  de_2y_yield: r.de_2y_yield,
  de_2y_d5_bps: r.de_2y_d5_bps,
  de_2y_d20_bps: r.de_2y_d20_bps,

  us_de_2y_spread: r.us_de_2y_spread,
  us_de_2y_spread_d5_bps: r.us_de_2y_spread_d5_bps,
  us_de_2y_spread_d20_bps: r.us_de_2y_spread_d20_bps,

  eurusd_price: r.eurusd_price,
  eurusd_d1_pct: r.eurusd_d1_pct,
  eurusd_d5_pct: r.eurusd_d5_pct,
  eurusd_d20_pct: r.eurusd_d20_pct,

  latest_ez_event: r.latest_ez_event,
  ez_composite_pmi: r.ez_composite_pmi,
  ez_composite_pmi_direction: r.ez_composite_pmi_direction,

  eur_usable: isUsableEurSnapshot(r)
}));

const eurInputPack = {
  agent_name: "EUR",
  layer: 1,
  isolation_rule: "This Layer 1 agent may only use this market snapshot and the EUR logic document. It must not read other agent outputs, dashboard data, Layer 2 outputs, or cross-agent synthesis.",
  execution_question: "Based on confirmed value-driving factors available at execution time, what is the likely direction of EUR?",

  snapshot_id: snapshot.id,
  snapshot_date: snapshot.snapshot_date,
  run_time_et: snapshot.run_time_et,
  created_at: snapshot.created_at || null,
  collector_version: snapshot.collector_version || null,
  source_status: snapshot.source_status || null,
  data_quality: quality,

  snapshot_selection: {
    selected_snapshot_id: snapshot.id,
    selected_run_time_et: snapshot.run_time_et,
    selected_created_at: snapshot.created_at || null,
    selected_snapshot_date: snapshot.snapshot_date,
    selected_from_rows: rows.length,
    selected_by: selectedBy,
    missing_required_inputs_for_eur: missingInputs,
    warnings: selectedInputWarnings,
    top_5_rows_seen_by_workflow: debugTopRows
  },

  available_inputs: {
    ecb_bias: requireInput("ecb_bias"),
    fed_bias: snapshot.fed_bias ?? null,

    de_2y_yield: requireInput("de_2y_yield"),
    de_2y_d5_bps: requireInput("de_2y_d5_bps"),
    de_2y_d20_bps: numOrNull(snapshot.de_2y_d20_bps),

    us_2y_yield: numOrNull(snapshot.us_2y_yield),
    us_2y_d5_bps: numOrNull(snapshot.us_2y_d5_bps),
    us_2y_d20_bps: numOrNull(snapshot.us_2y_d20_bps),

    us_de_2y_spread: requireInput("us_de_2y_spread"),
    us_de_2y_spread_d5_bps: requireInput("us_de_2y_spread_d5_bps"),
    us_de_2y_spread_d20_bps: numOrNull(snapshot.us_de_2y_spread_d20_bps),

    de_10y_yield: numOrNull(snapshot.de_10y_yield),
    de_10y_d5_bps: numOrNull(snapshot.de_10y_d5_bps),
    de_10y_d20_bps: numOrNull(snapshot.de_10y_d20_bps),

    us_de_10y_spread: numOrNull(snapshot.us_de_10y_spread),
    us_de_10y_spread_d5_bps: numOrNull(snapshot.us_de_10y_spread_d5_bps),
    us_de_10y_spread_d20_bps: numOrNull(snapshot.us_de_10y_spread_d20_bps),

    eurusd_price: requireInput("eurusd_price"),
    eurusd_d1_pct: requireInput("eurusd_d1_pct"),
    eurusd_d5_pct: requireInput("eurusd_d5_pct"),
    eurusd_d20_pct: numOrNull(snapshot.eurusd_d20_pct),

    dxy_level: requireInput("dxy_level"),
    dxy_d1: numOrNull(snapshot.dxy_d1),
    dxy_d5: numOrNull(snapshot.dxy_d5),
    dxy_d20: numOrNull(snapshot.dxy_d20),

    gold_price: numOrNull(snapshot.gold_price),
    gold_d1_pct: numOrNull(snapshot.gold_d1_pct),
    gold_d5_pct: numOrNull(goldD5),
    gold_d20_pct: numOrNull(snapshot.gold_d20_pct),

    vix_level: requireInput("vix_level"),
    vix_d1: numOrNull(snapshot.vix_d1),
    vix_d5: numOrNull(snapshot.vix_d5),

    latest_ez_event: parseMaybeJson(snapshot.latest_ez_event),
    latest_us_event: parseMaybeJson(snapshot.latest_us_event),
    upcoming_events: parseMaybeJson(snapshot.upcoming_events),

    ez_composite_pmi: numOrNull(snapshot.ez_composite_pmi),
    ez_composite_pmi_direction: snapshot.ez_composite_pmi_direction ?? null,
    ez_stress_flag: snapshot.ez_stress_flag ?? null,

    global_growth_regime: snapshot.global_growth_regime ?? null,
    china_growth_signal: snapshot.china_growth_signal ?? null,

    equities_regime: snapshot.equities_regime ?? null
  },

  missing_inputs_must_be_scored_neutral: [
    "ecb_bias if unavailable",
    "de_2y_d5_bps or de_2y_d20_bps if unavailable",
    "us_de_2y_spread_d5_bps or us_de_2y_spread_d20_bps if unavailable",
    "latest_ez_event if unavailable",
    "ez_composite_pmi or ez_composite_pmi_direction if unavailable",
    "eurusd_d1_pct, eurusd_d5_pct or eurusd_d20_pct if unavailable",
    "gold_d5_pct or gold_d20_pct if unavailable",
    "ez_stress_flag if unavailable",
    "global_growth_regime or china_growth_signal if unavailable",
    "vix_level, vix_d1 or vix_d5 if unavailable"
  ],

  eur_factor_map: {
    F1: "ECB Bias / Policy Delta",
    F2: "Germany 2Y Yield Delta",
    F3: "US-DE 2Y Spread Delta",
    F4: "Eurozone Economic Surprise",
    F5: "Eurozone PMI Trend",
    F6: "EUR Own Price Delta",
    F7: "Gold Confirmation",
    F8: "Eurozone Stress Risk",
    F9: "Global Growth Regime",
    F10: "Risk Appetite / VIX Regime"
  }
};

return [{ json: eurInputPack }];

const openAiItem = $input.first().json;

let raw =
  openAiItem.output?.[0]?.content?.[0]?.text ??
  openAiItem.output?.[0]?.content?.[0] ??
  openAiItem.text ??
  openAiItem.message ??
  openAiItem;

if (!raw) {
  throw new Error('No OpenAI output found');
}

let report;

if (typeof raw === 'object') {
  report = raw;
} else {
  try {
    report = JSON.parse(String(raw));
  } catch (error) {
    throw new Error(`OpenAI returned invalid JSON: ${error.message}. Raw text: ${String(raw).slice(0, 1000)}`);
  }
}

const marketSnapshot = $('Build EUR Input Pack').first().json || {};
const marketInputs = marketSnapshot.available_inputs || {};

function pct(value) {
  if (value === null || value === undefined || value === '') return null;
  const match = String(value).match(/(\d+(\.\d+)?)/);
  return match ? Number(match[1]) : null;
}

function reasonFor(tf) {
  return (
    report[`${tf}_reason`] ||
    report[`reason_${tf}`] ||
    report.reasoning_summary ||
    ''
  );
}

return [
  {
    json: {
      snapshot_id: marketSnapshot.snapshot_id || null,
      agent_name: 'EUR',
      layer: 1,

      run_time_et: marketSnapshot.run_time_et || new Date().toISOString(),
      snapshot_date: marketSnapshot.snapshot_date || new Date().toISOString().slice(0, 10),

      market_inputs: marketInputs,
      snapshot_selection: marketSnapshot.snapshot_selection || null,

      call_24h_direction: report.direction_24h || null,
      call_24h_conviction: pct(report.conviction_24h),
      call_24h_reason: reasonFor('24h'),

      call_3d_direction: report.direction_3_day || null,
      call_3d_conviction: pct(report.conviction_3_day),
      call_3d_reason: reasonFor('3d'),

      call_current_week_direction: report.direction_current_week || null,
      call_current_week_conviction: pct(report.conviction_current_week),
      call_current_week_reason: reasonFor('current_week'),

      call_next_week_direction: report.direction_next_week || null,
      call_next_week_conviction: pct(report.conviction_next_week),
      call_next_week_reason: reasonFor('next_week'),

      call_current_month_direction: report.direction_current_month || null,
      call_current_month_conviction: pct(report.conviction_current_month),
      call_current_month_reason: reasonFor('current_month'),

      direction_24h: report.direction_24h || null,
      conviction_24h: pct(report.conviction_24h),

      direction_3_day: report.direction_3_day || null,
      conviction_3_day: pct(report.conviction_3_day),

      direction_current_week: report.direction_current_week || null,
      conviction_current_week: pct(report.conviction_current_week),

      direction_next_week: report.direction_next_week || null,
      conviction_next_week: pct(report.conviction_next_week),

      direction_current_month: report.direction_current_month || null,
      conviction_current_month: pct(report.conviction_current_month),

      factor_breakdown: report.factor_breakdown || {},

      warnings: report.risk_flags || report.warnings || [],

      full_output: {
        ...report,
        market_inputs_seen_by_workflow: marketInputs,
        snapshot_selection: marketSnapshot.snapshot_selection || null
      },

      raw_agent_output: report,

      logic_document: 'agent_eur_direction.md',
      logic_document_version: report.logic_document_version || '2.0_weighted_engine',

      reasoning_summary: report.reasoning_summary || '',

      score_bullish: report.score_bullish ?? null,
      score_bearish: report.score_bearish ?? null,
      score_neutral: report.score_neutral ?? null
    }
  }
];

const item = $input.first().json;
const inputs = item.market_inputs || {};

function hasValue(v) {
  return v !== null && v !== undefined && v !== "";
}

function n(v) {
  if (!hasValue(v)) return null;
  const x = Number(v);
  return Number.isFinite(x) ? x : null;
}

function makeFactor(signal, evidence, reason) {
  return { signal, evidence, reason };
}

function pctLabel(v) {
  const x = n(v);
  return x === null ? "missing" : `${Math.round(x * 100) / 100}`;
}

const TIMEFRAME_WEIGHTS = {
  "24h": { F1: 20, F2: 18, F3: 20, F4: 14, F5: 4, F6: 12, F7: 4, F8: 4, F9: 2, F10: 2 },
  "3d": { F1: 18, F2: 18, F3: 20, F4: 10, F5: 8, F6: 10, F7: 4, F8: 5, F9: 4, F10: 3 },
  "current_week": { F1: 18, F2: 14, F3: 22, F4: 8, F5: 12, F6: 8, F7: 4, F8: 8, F9: 4, F10: 2 },
  "next_week": { F1: 18, F2: 12, F3: 24, F4: 5, F5: 14, F6: 6, F7: 3, F8: 10, F9: 6, F10: 2 },
  "current_month": { F1: 16, F2: 12, F3: 22, F4: 5, F5: 16, F6: 8, F7: 3, F8: 10, F9: 6, F10: 2 }
};

function chooseDelta(tf, d1, d5, d20) {
  if (tf === "24h" && n(d1) !== null) return d1;
  if ((tf === "next_week" || tf === "current_month") && n(d20) !== null) return d20;
  if (n(d5) !== null) return d5;
  if (n(d1) !== null) return d1;
  return null;
}

function latestEzEventSignal() {
  const ev = inputs.latest_ez_event;
  const text = JSON.stringify(ev || {}).toLowerCase();

  if (!ev) return makeFactor("NEUTRAL", "No recent Eurozone event", "No confirmed EZ economic surprise");
  if (text.includes("bullish") || text.includes("positive") || text.includes("beat")) {
    return makeFactor("BULLISH", JSON.stringify(ev), "Positive Eurozone surprise supports EUR");
  }
  if (text.includes("bearish") || text.includes("negative") || text.includes("miss")) {
    return makeFactor("BEARISH", JSON.stringify(ev), "Negative Eurozone surprise pressures EUR");
  }

  return makeFactor("NEUTRAL", JSON.stringify(ev), "No clear EUR economic surprise signal");
}

function factorSignals(tf) {
  const ecb = String(inputs.ecb_bias || "").toLowerCase();

  const de2yDelta = chooseDelta(tf, null, inputs.de_2y_d5_bps, inputs.de_2y_d20_bps);
  const spreadDelta = chooseDelta(tf, null, inputs.us_de_2y_spread_d5_bps, inputs.us_de_2y_spread_d20_bps);
  const eurDelta = chooseDelta(tf, inputs.eurusd_d1_pct, inputs.eurusd_d5_pct, inputs.eurusd_d20_pct);
  const goldDelta = chooseDelta(tf, inputs.gold_d1_pct, inputs.gold_d5_pct, inputs.gold_d20_pct);

  const vix = n(inputs.vix_level);
  const pmi = n(inputs.ez_composite_pmi);
  const pmiDirection = String(inputs.ez_composite_pmi_direction || "").toLowerCase();
  const stress = String(inputs.ez_stress_flag || "").toLowerCase();
  const growth = String(inputs.global_growth_regime || inputs.china_growth_signal || "").toLowerCase();

  const signals = {};

  signals.F1 = (() => {
    if (!ecb || ecb === "unknown") return makeFactor("NEUTRAL", "ECB bias unknown", "Missing input");
    if (ecb.includes("hawkish")) return makeFactor("BULLISH", `ECB bias ${ecb}`, "Hawkish ECB bias supports EUR");
    if (ecb.includes("dovish")) return makeFactor("BEARISH", `ECB bias ${ecb}`, "Dovish ECB bias pressures EUR");
    return makeFactor("NEUTRAL", `ECB bias ${ecb}`, "No clear ECB impulse");
  })();

  signals.F2 = (() => {
    const d = n(de2yDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing Germany 2Y delta", "Missing input");
    if (d >= 5) return makeFactor("BULLISH", `Germany 2Y delta ${pctLabel(d)} bps`, "Rising German front-end yields support EUR");
    if (d <= -5) return makeFactor("BEARISH", `Germany 2Y delta ${pctLabel(d)} bps`, "Falling German front-end yields pressure EUR");
    return makeFactor("NEUTRAL", `Germany 2Y delta ${pctLabel(d)} bps`, "German 2Y move below threshold");
  })();

  signals.F3 = (() => {
    const d = n(spreadDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing US-DE 2Y spread delta", "Missing input");
    if (d <= -5) return makeFactor("BULLISH", `US-DE 2Y spread delta ${pctLabel(d)} bps`, "US-DE spread narrowing supports EUR");
    if (d >= 5) return makeFactor("BEARISH", `US-DE 2Y spread delta ${pctLabel(d)} bps`, "US-DE spread widening pressures EUR");
    return makeFactor("NEUTRAL", `US-DE 2Y spread delta ${pctLabel(d)} bps`, "Spread move below threshold");
  })();

  signals.F4 = latestEzEventSignal();

  signals.F5 = (() => {
    if (pmi === null && !pmiDirection) return makeFactor("NEUTRAL", "Missing EZ PMI trend", "Missing input");
    if ((pmi !== null && pmi > 50 && pmiDirection.includes("rising")) || pmiDirection.includes("improving")) {
      return makeFactor("BULLISH", `EZ PMI ${pmi ?? "unknown"} ${pmiDirection}`, "Improving Eurozone PMI trend supports EUR");
    }
    if ((pmi !== null && pmi < 50) || pmiDirection.includes("falling") || pmiDirection.includes("deteriorating")) {
      return makeFactor("BEARISH", `EZ PMI ${pmi ?? "unknown"} ${pmiDirection}`, "Weak or deteriorating Eurozone PMI trend pressures EUR");
    }
    return makeFactor("NEUTRAL", `EZ PMI ${pmi ?? "unknown"} ${pmiDirection}`, "PMI trend not decisive");
  })();

  signals.F6 = (() => {
    const d = n(eurDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing EURUSD delta", "Missing input");
    const upThreshold = tf === "24h" ? 0.2 : 0.5;
    const downThreshold = tf === "24h" ? -0.2 : -0.5;
    if (d >= upThreshold) return makeFactor("BULLISH", `EURUSD delta ${pctLabel(d)}%`, "EUR own price delta confirms bullish pressure");
    if (d <= downThreshold) return makeFactor("BEARISH", `EURUSD delta ${pctLabel(d)}%`, "EUR own price delta confirms bearish pressure");
    return makeFactor("NEUTRAL", `EURUSD delta ${pctLabel(d)}%`, "EUR own price move below threshold");
  })();

  signals.F7 = (() => {
    const d = n(goldDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing gold delta", "Missing input");
    const upThreshold = tf === "24h" ? 0.3 : 0.75;
    const downThreshold = tf === "24h" ? -0.3 : -0.75;
    if (d >= upThreshold) return makeFactor("BULLISH", `Gold delta ${pctLabel(d)}%`, "Gold strength confirms anti-USD pressure supportive for EUR");
    if (d <= downThreshold) return makeFactor("BEARISH", `Gold delta ${pctLabel(d)}%`, "Gold weakness confirms USD strength pressure against EUR");
    return makeFactor("NEUTRAL", `Gold delta ${pctLabel(d)}%`, "Gold move below confirmation threshold");
  })();

  signals.F8 = (() => {
    if (!stress || stress === "null" || stress === "unknown") {
      return makeFactor("NEUTRAL", "EZ stress unavailable", "Missing or inactive stress input");
    }
    if (stress.includes("active") || stress.includes("true") || stress.includes("elevated") || stress.includes("risk") || stress.includes("stress")) {
      return makeFactor("BEARISH", `EZ stress ${stress}`, "Eurozone stress is bearish EUR");
    }
    return makeFactor("NEUTRAL", `EZ stress ${stress}`, "No active Eurozone stress signal");
  })();

  signals.F9 = (() => {
    if (!growth || growth === "null" || growth === "unknown") {
      return makeFactor("NEUTRAL", "Global growth unavailable", "Missing input");
    }
    if (growth.includes("expanding") || growth.includes("positive") || growth.includes("improving") || growth.includes("risk_on")) {
      return makeFactor("BULLISH", `Growth regime ${growth}`, "Global growth expansion supports EUR");
    }
    if (growth.includes("contracting") || growth.includes("negative") || growth.includes("deteriorating") || growth.includes("risk_off")) {
      return makeFactor("BEARISH", `Growth regime ${growth}`, "Global growth deterioration pressures EUR");
    }
    return makeFactor("NEUTRAL", `Growth regime ${growth}`, "Global growth signal mixed");
  })();

  signals.F10 = (() => {
    if (vix === null) return makeFactor("NEUTRAL", "Missing VIX", "Missing input");
    if (vix < 16) return makeFactor("BULLISH", `VIX ${vix}`, "Risk-on regime supports EUR versus safe-haven USD");
    if (vix > 25) return makeFactor("BEARISH", `VIX ${vix}`, "Risk-off regime favours USD over EUR");
    return makeFactor("NEUTRAL", `VIX ${vix}`, "Neutral risk regime");
  })();

  return signals;
}

function scoreTimeframe(tf) {
  const weights = TIMEFRAME_WEIGHTS[tf];
  const signals = factorSignals(tf);

  let bullish = 0;
  let bearish = 0;
  let neutral = 0;
  let bullishCount = 0;
  let bearishCount = 0;
  let neutralCount = 0;

  const factorBreakdown = {};

  for (const [id, sig] of Object.entries(signals)) {
    const weight = weights[id] || 0;
    factorBreakdown[id] = { ...sig, weight };

    if (sig.signal === "BULLISH") {
      bullish += weight;
      bullishCount++;
    } else if (sig.signal === "BEARISH") {
      bearish += weight;
      bearishCount++;
    } else {
      neutral += weight;
      neutralCount++;
    }
  }

  const active = bullish + bearish;
  const bullishArgument = active > 0 ? Math.round((bullish / active) * 100) : 0;
  const bearishArgument = active > 0 ? Math.round((bearish / active) * 100) : 0;
  const neutralPct = Math.round(neutral);
  const directionalParticipationPct = Math.round(active);
  const netEdge = bullishArgument - bearishArgument;

  const baseDirection =
    bullish > bearish ? "BULLISH" :
    bearish > bullish ? "BEARISH" :
    "NO_CLEAR_BIAS";

  const absEdge = Math.abs(netEdge);

  const direction =
    baseDirection === "NO_CLEAR_BIAS" ? "NO_CLEAR_BIAS" :
    absEdge < 20 ? `${baseDirection}_LEAN` :
    baseDirection;

  const conviction =
    baseDirection === "BULLISH" ? bullishArgument :
    baseDirection === "BEARISH" ? bearishArgument :
    0;

  const strength =
    absEdge >= 40 ? "VERY_STRONG" :
    absEdge >= 25 ? "STRONG" :
    absEdge >= 15 ? "MODERATE" :
    "WEAK";

  const reason = `${tf} EUR deterministic score: bull case ${bullishArgument}%, bear case ${bearishArgument}%, neutral/inactive ${neutralPct}%, directional participation ${directionalParticipationPct}%, net edge ${netEdge > 0 ? "+" : ""}${netEdge}.`;

  return {
    direction,
    conviction,
    reason,
    factor_breakdown: factorBreakdown,
    score_bullish: bullishCount,
    score_bearish: bearishCount,
    score_neutral: neutralCount,
    weighted_score: {
      bullish_weight: bullish,
